// Import all icons
import beerIcon from '../Icons/beer.png';
import cocktailIcon from '../Icons/cocktail.png';
import coffeeIcon from '../Icons/coffee.png';
import juicesIcon from '../Icons/juices.png';
import mocktailsIcon from '../Icons/mocktails.png';
import softdrinksIcon from '../Icons/softdrinks.png';
import spiritsIcon from '../Icons/spirits.png';
import sportdrinksIcon from '../Icons/sportdrinks.png';
import teaIcon from '../Icons/tea.png';
import wineIcon from '../Icons/wine.png';

// Define the options
const optionbarOptions = [
    { id: 'beer', label: 'Beer', checked: true, icon: beerIcon },
    { id: 'cocktail', label: 'Cocktail', checked: true, icon: cocktailIcon },
    { id: 'coffee', label: 'Coffee', checked: true, icon: coffeeIcon },
    { id: 'juices', label: 'Juices', checked: true, icon: juicesIcon },
    { id: 'mocktails', label: 'Mocktails', checked: true, icon: mocktailsIcon },
    { id: 'softdrinks', label: 'Soft Drinks', checked: true, icon: softdrinksIcon },
    { id: 'spirits', label: 'Spirits', checked: true, icon: spiritsIcon },
    { id: 'sportdrinks', label: 'Sport/Energy Drinks', checked: true, icon: sportdrinksIcon },
    { id: 'tea', label: 'Tea & Infusions', checked: true, icon: teaIcon },
    { id: 'wine', label: 'Wine', checked: true, icon: wineIcon },
];

export default optionbarOptions;
